import React, { useEffect, useState } from "react";
import Navbar from "../components/Navbar";
import { api } from "../lib/api";
import { ArrowUpRight } from "lucide-react";

export default function Projects() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      try {
        const r = await api.get("/projects");
        setProjects(r.data);
      } finally { setLoading(false); }
    })();
  }, []);

  const STATUS_LABEL = { in_progress: "in progress", completed: "completed", planned: "planned" };

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-6xl mx-auto px-6 md:px-10 pt-12 pb-16">
        <p className="text-white/50 text-sm mb-2">our work</p>
        <h1 className="hero-title text-6xl md:text-8xl font-medium mb-2" data-testid="projects-title">projects</h1>
        <p className="text-white/60 max-w-xl mb-12">things we're building and have built — from kernels to ml pipelines, from playful prototypes to production tools.</p>

        {loading ? (
          <p className="text-white/40 text-sm">loading...</p>
        ) : projects.length === 0 ? (
          <div className="border border-dashed border-white/15 rounded-3xl p-16 text-center">
            <p className="text-2xl text-white/70 mb-2">coming soon</p>
            <p className="text-white/40 text-sm">our members are forging something. check back shortly.</p>
          </div>
        ) : (
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-5" data-testid="projects-grid">
            {projects.map((p) => (
              <article key={p.id} className="group bg-neutral-900/60 border border-white/10 rounded-3xl overflow-hidden hover:border-white/30 transition-colors" data-testid={`project-card-${p.id}`}>
                {p.image_url && (
                  <div className="aspect-[16/10] bg-black overflow-hidden">
                    <img src={p.image_url} alt={p.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                  </div>
                )}
                <div className="p-5">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[10px] uppercase tracking-wider text-white/50 bg-white/5 px-2 py-0.5 rounded-full">{STATUS_LABEL[p.status]}</span>
                    {p.repo_url && (
                      <a href={p.repo_url} target="_blank" rel="noreferrer" className="text-white/40 hover:text-white"><ArrowUpRight size={16} /></a>
                    )}
                  </div>
                  <h3 className="text-lg font-medium mb-1.5">{p.title}</h3>
                  <p className="text-sm text-white/60 mb-3 line-clamp-3">{p.description}</p>
                  <div className="flex items-center justify-between">
                    <p className="text-xs text-white/40">by {p.owner_name || "spectral forge"}</p>
                    {p.tags?.length > 0 && (
                      <div className="flex gap-1">
                        {p.tags.slice(0, 2).map((t) => <span key={t} className="text-[10px] text-white/50">#{t}</span>)}
                      </div>
                    )}
                  </div>
                </div>
              </article>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
